export function nextGeneration(cells: Cell[]): Cell[] {
  const live = new Set(cells.map(([x, y]) => key(x, y)));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const cell: Cell = [x + dx, y + dy];
      const k = key(cell[0], cell[1]);
      const entry = neighborCounts.get(k) ?? { cell, count: 0 };
      entry.count++;
      neighborCounts.set(k, entry);
    }
  }

  const survives = (k: string, count: number) =>
    count === 3 || (count === 2 && live.has(k));

  const result: Cell[] = [];
  for (const [k, { cell, count }] of neighborCounts) {
    if (survives(k, count)) result.push(cell);
  }
  return result;
}
